function UISkyBlockProductSellPreciousTip:onShowPreciousTipDialog(itemId, itemMeta, type, callBack)
    self.callBack = callBack
    self:show()
    local meta = itemMeta
    if SellPreciousTipConfig:isSpItemMeta(itemId) then
        meta = 0
    end
    GuiItemStack.showItemIcon(self.icon, tonumber(itemId), tonumber(meta), "")
    self.type = type
    local str = "drop_precious_tip"
    if self.type == 1 then
        if itemId == 2802 or itemId == 2803 then
            str = "sell_christmas_gift_tip"
        else
            str = "sell_precious_tip"
        end
    else
        if itemId == 2802 or itemId == 2803 then
            str = "drop_christmas_gift_tip"
        else
            str = "drop_precious_tip"
        end
    end
    self.message:SetText(Lang:getString(str))
end


